"""
Represents the checkers board.
"""

class Board:
    def __init__(self):
        self.grid = [[' ' for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        for row in range(3, 5):
            for col in range(1 if row % 2 == 0 else 0, 8, 2):
                self.grid[row][col] = 'R'
        for row in range(5, 7):
            for col in range(0 if row % 2 == 0 else 1, 8, 2):
                self.grid[row][col] = 'B'

    def display(self):
        print('  A B C D E F G H')
        for i, row in enumerate(self.grid, start=1):
            print(f"{i} {' '.join(row)}")

    def move_piece(self, from_pos, to_pos):
        x_from, y_from = ord(from_pos[0]) - ord('A'), int(from_pos[1]) - 1
        x_to, y_to = ord(to_pos[0]) - ord('A'), int(to_pos[1]) - 1
        self.grid[x_to][y_to] = self.grid[x_from][y_from]
        self.grid[x_from][y_from] = ' '

    def is_valid_move(self, from_pos, to_pos):
        x_from, y_from = ord(from_pos[0]) - ord('A'), int(from_pos[1]) - 1
        x_to, y_to = ord(to_pos[0]) - ord('A'), int(to_pos[1]) - 1

        if abs(x_to - x_from) != 2 or abs(y_to - y_from) != 2:
            return False

        if self.grid[x_to][y_to] != ' ':
            return False

        mid_x, mid_y = (x_from + x_to) // 2, (y_from + y_to) // 2
        return self.grid[mid_x][mid_y] != ' '
```

